const j = $input.item.json;
const content = j.content || j.output_text || j.message?.content || j.text || (Array.isArray(j.output) ? j.output.map(o => o.content?.[0]?.text || '').join('') : '') || '';

let notaSOAP;
try {
  const cleaned = String(content).replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  notaSOAP = JSON.parse(cleaned);
} catch (e) {
  notaSOAP = { error: 'No se pudo estructurar la nota', transcripcion_raw: content };
}

// Asegura que 'remision' siempre exista con una forma válida, aunque el modelo la omita
if (!notaSOAP.remision || typeof notaSOAP.remision !== 'object') {
  notaSOAP.remision = { aplica: false, examenes_sugeridos: '', especialidad_sugerida: '' };
}

// Metadatos de la consulta: id único (para historial/decisión médica) y fecha de creación
const body = $('Webhook').item.json.body || {};
notaSOAP.id = body.id || (Date.now() + '-' + Math.random().toString(36).slice(2, 8));
notaSOAP._creadoEn = new Date().toISOString();

return { json: notaSOAP };

const fs = require('fs');
const path = require('path');

const dir = '/data/historial';
try { fs.mkdirSync(dir, { recursive: true }); } catch (e) {}

const data = $input.item.json;
const filePath = path.join(dir, `${data.id}.json`);

try {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), 'utf-8');
} catch (e) {
  data._guardadoError = e.message;
}

return { json: data };

const fs = require('fs');
const path = require('path');
const dir = '/data/historial';

let registros = [];
try {
  const files = fs.readdirSync(dir).filter(f => f.endsWith('.json'));
  registros = files.map(f => {
    try { return JSON.parse(fs.readFileSync(path.join(dir, f), 'utf-8')); }
    catch (e) { return null; }
  }).filter(Boolean);
} catch (e) {
  registros = [];
}

registros.sort((a, b) => new Date(b._creadoEn || 0) - new Date(a._creadoEn || 0));

return { json: { registros } };

const fs = require('fs');
const path = require('path');
const dir = '/data/historial';

const body = $input.item.json.body || {};
const id = body.id;

if (!id) {
  return { json: { error: 'Falta el id de la consulta' } };
}

const filePath = path.join(dir, `${id}.json`);
let data;
try {
  data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
} catch (e) {
  return { json: { error: 'No se encontró la consulta con ese id' } };
}

data.remision = data.remision || { aplica: false, examenes_sugeridos: '', especialidad_sugerida: '' };
data.remision.decision_medica = {
  estado: body.estado || 'pendiente',
  especialidad_final: body.especialidad_final || data.remision.especialidad_sugerida || '',
  observacion: body.observacion || '',
  decididoEn: new Date().toISOString()
};

try {
  fs.writeFileSync(filePath, JSON.stringify(data, null, 2), 'utf-8');
} catch (e) {
  data._guardadoError = e.message;
}

return { json: data };
